import{c as d,Q as e,j as a,m as o}from"./chunks/framework.DVkeSyfh.js";const h=JSON.parse('{"title":"Справочник Web API","description":"","frontmatter":{},"headers":[],"relativePath":"ru/api.md","filePath":"ru/api.md","lastUpdated":1780001723000}'),r={name:"ru/api.md"};function c(s,t,i,l,n,p){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="справочник-web-api" tabindex="-1">Справочник Web API <a class="header-anchor" href="#справочник-web-api" aria-label="Permalink to &quot;Справочник Web API&quot;">​</a></h1><p>Эта страница документирует FastAPI endpoints, используемые frontend. Большинству пользователей не нужно вызывать эти endpoints напрямую; используйте страницу для debugging web UI, интеграции local script или проверки, какое backend action использует UI button.</p><h2 id="справочник-web-api-1" tabindex="-1">Справочник Web API <a class="header-anchor" href="#справочник-web-api-1" aria-label="Permalink to &quot;Справочник Web API&quot;">​</a></h2><p>Frontend вызывает эти endpoints через <code>frontend/src/api.ts</code>.</p><p>API local-first. Endpoints для scan, analyze, search, preview, export, reset, clear или relocate работают с выбранной SQLite database и local filesystem paths. Запись в аудиофайлы происходит только через явные MAEST genre tag endpoints.</p><h3 id="database" tabindex="-1">Database <a class="header-anchor" href="#database" aria-label="Permalink to &quot;Database&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/api/database/current</code></td><td>Вернуть состояние выбранной database.</td></tr><tr><td><code>POST</code></td><td><code>/api/database/switch</code></td><td>Переключиться на database path.</td></tr><tr><td><code>POST</code></td><td><code>/api/database/dialog</code></td><td>Открыть локальный dialog выбора database.</td></tr><tr><td><code>POST</code></td><td><code>/api/database/clear</code></td><td>Очистить local SQLite tracks, embeddings и dependent classifier scores.</td></tr></tbody></table><p>Используйте эти endpoints при выборе active library database. <code>clear</code> - database operation, а не удаление аудиофайлов, но он удаляет library index и analysis rows из выбранного SQLite file.</p><h3 id="library" tabindex="-1">Library <a class="header-anchor" href="#library" aria-label="Permalink to &quot;Library&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td><code>POST</code></td><td><code>/api/library/scan</code></td><td>Запустить scan job для root folder.</td></tr><tr><td><code>POST</code></td><td><code>/api/library/tags/refresh</code></td><td>Запустить Mutagen tag refresh job.</td></tr><tr><td><code>POST</code></td><td><code>/api/library/relocate</code></td><td>Preview или apply stored path relocation.</td></tr><tr><td><code>GET</code></td><td><code>/api/library/summary</code></td><td>Вернуть counters для tracks и analysis families.</td></tr><tr><td><code>GET</code></td><td><code>/api/tracks</code></td><td>Вернуть paginated/searchable track page.</td></tr><tr><td><code>GET</code></td><td><code>/api/tracks/{track_id}</code></td><td>Вернуть один full track payload.</td></tr><tr><td><code>POST</code></td><td><code>/api/tracks/filtered</code></td><td>Вернуть filtered track rows для selection workflows.</td></tr></tbody></table><p><code>/api/tracks</code> и <code>/api/tracks/filtered</code> принимают <code>preset=syncopated</code>, чтобы фильтровать по stored MAEST syncopated-rhythm flag. Они также принимают classifier threshold maps для filtering tracks по stored classifier scores.</p><p>Используйте <code>/api/tracks</code> для paged browsing, а <code>/api/tracks/{track_id}</code> только когда full metadata dialog нужен один track. Это сохраняет responsiveness для больших libraries.</p><h3 id="jobs" tabindex="-1">Jobs <a class="header-anchor" href="#jobs" aria-label="Permalink to &quot;Jobs&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/api/library/scan/jobs/latest</code></td><td>Вернуть latest scan или tag-refresh job.</td></tr><tr><td><code>GET</code></td><td><code>/api/library/scan/jobs/{job_id}</code></td><td>Вернуть одну scan job.</td></tr><tr><td><code>POST</code></td><td><code>/api/library/scan/jobs/{job_id}/cancel</code></td><td>Запросить scan cancellation.</td></tr><tr><td><code>GET</code></td><td><code>/api/analyze/jobs/latest</code></td><td>Вернуть latest MERT/CLAP analysis job.</td></tr><tr><td><code>GET</code></td><td><code>/api/analyze/jobs/{job_id}</code></td><td>Вернуть одну MERT/CLAP analysis job.</td></tr><tr><td><code>POST</code></td><td><code>/api/analyze/jobs/{job_id}/cancel</code></td><td>Запросить MERT/CLAP cancellation.</td></tr><tr><td><code>GET</code></td><td><code>/api/sonara/analyze/jobs/latest</code></td><td>Вернуть latest Sonara job.</td></tr><tr><td><code>GET</code></td><td><code>/api/sonara/analyze/jobs/{job_id}</code></td><td>Вернуть одну Sonara job.</td></tr><tr><td><code>POST</code></td><td><code>/api/sonara/analyze/jobs/{job_id}/cancel</code></td><td>Запросить Sonara cancellation.</td></tr><tr><td><code>GET</code></td><td><code>/api/genres/analyze/jobs/latest</code></td><td>Вернуть latest MAEST job.</td></tr><tr><td><code>GET</code></td><td><code>/api/genres/analyze/jobs/{job_id}</code></td><td>Вернуть одну MAEST job.</td></tr><tr><td><code>POST</code></td><td><code>/api/genres/analyze/jobs/{job_id}/cancel</code></td><td>Запросить MAEST cancellation.</td></tr><tr><td><code>GET</code></td><td><code>/api/classifiers/{classifier_key}/analyze/jobs/latest</code></td><td>Вернуть latest classifier job.</td></tr><tr><td><code>GET</code></td><td><code>/api/classifiers/{classifier_key}/analyze/jobs/{job_id}</code></td><td>Вернуть одну classifier job.</td></tr><tr><td><code>POST</code></td><td><code>/api/classifiers/{classifier_key}/analyze/jobs/{job_id}/cancel</code></td><td>Запросить classifier cancellation.</td></tr><tr><td><code>GET</code></td><td><code>/api/tags/genres/jobs/latest</code></td><td>Вернуть latest genre tag write job.</td></tr><tr><td><code>GET</code></td><td><code>/api/tags/genres/jobs/{job_id}</code></td><td>Вернуть одну genre tag write job.</td></tr><tr><td><code>POST</code></td><td><code>/api/tags/genres/jobs/{job_id}/cancel</code></td><td>Запросить genre tag write cancellation.</td></tr></tbody></table><p>Job endpoints позволяют frontend poll long-running work и запрашивать cancellation. Cancellation cooperative: job может закончить текущий track или batch перед остановкой.</p><h3 id="analysis-and-search" tabindex="-1">Analysis and search <a class="header-anchor" href="#analysis-and-search" aria-label="Permalink to &quot;Analysis and search&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td><code>POST</code></td><td><code>/api/analyze</code></td><td>Запустить MERT или CLAP embedding analysis.</td></tr><tr><td><code>POST</code></td><td><code>/api/sonara/analyze</code></td><td>Запустить Sonara feature analysis.</td></tr><tr><td><code>POST</code></td><td><code>/api/genres/analyze</code></td><td>Запустить MAEST genre analysis.</td></tr><tr><td><code>POST</code></td><td><code>/api/classifiers/{classifier_key}/analyze</code></td><td>Запустить classifier scoring.</td></tr><tr><td><code>POST</code></td><td><code>/api/analysis/reset</code></td><td>Reset одного analysis family.</td></tr><tr><td><code>POST</code></td><td><code>/api/search</code></td><td>Search in MERT embedding space.</td></tr><tr><td><code>POST</code></td><td><code>/api/search/sonara</code></td><td>Search with Sonara features.</td></tr><tr><td><code>POST</code></td><td><code>/api/search/text</code></td><td>Search CLAP audio vectors from text.</td></tr></tbody></table><p>Используйте analysis endpoints перед search endpoints, если library еще не processed. Empty search results часто означают, что у candidate tracks нет нужных Sonara features, MERT embeddings или CLAP embeddings.</p><h3 id="export-tags-dialogs-media" tabindex="-1">Export, tags, dialogs, media <a class="header-anchor" href="#export-tags-dialogs-media" aria-label="Permalink to &quot;Export, tags, dialogs, media&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td><code>POST</code></td><td><code>/api/export</code></td><td>Export selected tracks as M3U or CSV.</td></tr><tr><td><code>POST</code></td><td><code>/api/tags/genres/apply</code></td><td>Apply MAEST genres immediately.</td></tr><tr><td><code>POST</code></td><td><code>/api/tags/genres/jobs</code></td><td>Start cancellable MAEST genre tag write job.</td></tr><tr><td><code>POST</code></td><td><code>/api/dialog/folder</code></td><td>Open a folder chooser dialog.</td></tr><tr><td><code>GET</code></td><td><code>/media/{track_id}</code></td><td>Serve browser-playable audio for one track.</td></tr></tbody></table><p>Frontend preview player использует <code>/media/{track_id}</code> и запускает playback после click по preview button. AIFF/AIF responses транскодируются во временные WAV files для browser compatibility и scrubbing support без перезаписи source audio.</p><p>Используйте <code>/api/export</code> для playlist/report files. Используйте <code>/api/tags/genres/jobs</code> для больших genre writes, чтобы были progress и cancellation; оставляйте <code>/api/tags/genres/apply</code> для немедленных малых writes.</p>',22)])])}const y=d(r,[["render",c]]);export{h as __pageData,y as default};
